package org.eclipse.rdf4j.query.algebra.evaluation.sketch;

import static org.junit.jupiter.api.Assertions.assertEquals;

import org.junit.jupiter.api.Test;

class FastAgmsFrequencySketchTest {

	private static final long SEED = 0x51E7C0DEL;

	@Test
	void innerProductCacheMissesAfterLocalUpdate() {
		FastAgmsFrequencySketch left = new FastAgmsFrequencySketch(1, 1, SEED);
		FastAgmsFrequencySketch right = new FastAgmsFrequencySketch(1, 1, SEED);
		left.update(11L, 2L);
		right.update(11L, 3L);

		assertEquals(6.0d, left.innerProduct(right), 0.0d);

		left.update(11L, 4L);

		assertEquals(18.0d, left.innerProduct(right), 0.0d);
	}

	@Test
	void innerProductCacheMissesAfterRemoteUpdate() {
		FastAgmsFrequencySketch left = new FastAgmsFrequencySketch(1, 1, SEED);
		FastAgmsFrequencySketch right = new FastAgmsFrequencySketch(1, 1, SEED);
		left.update(11L, 2L);
		right.update(11L, 3L);

		assertEquals(6.0d, left.innerProduct(right), 0.0d);

		right.update(11L, 4L);

		assertEquals(14.0d, left.innerProduct(right), 0.0d);
	}

	@Test
	void innerProductCacheMissesAfterAddScaled() {
		FastAgmsFrequencySketch left = new FastAgmsFrequencySketch(1, 1, SEED);
		FastAgmsFrequencySketch right = new FastAgmsFrequencySketch(1, 1, SEED);
		FastAgmsFrequencySketch addition = new FastAgmsFrequencySketch(1, 1, SEED);
		left.update(11L, 2L);
		right.update(11L, 3L);
		addition.update(11L, 5L);

		assertEquals(6.0d, left.innerProduct(right), 0.0d);

		left.addScaled(addition, 2L);

		assertEquals(36.0d, left.innerProduct(right), 0.0d);
	}
}
